namespace sv_7fe716eec7434f6a9a1579d2874b5583.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        var doctors = new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Patel",
            "Dr. Lee"
        };
        return Task.FromResult(doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        var slots = new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        };
        return Task.FromResult(slots);
    }

    /// <summary>
    /// Validates patient data against server-side business rules.
    /// Returns a dictionary of field name → error message for any failures.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = "Account has outstanding balance";
        }

        if (string.Equals(insuranceProvider, "None", StringComparison.Ordinal)
            && string.Equals(doctor, "Dr. Smith", StringComparison.Ordinal))
        {
            errors["PreferredDoctor"] = "Selected doctor does not accept self-pay patients";
        }

        if (string.Equals(timeSlot, "10:00 AM", StringComparison.Ordinal))
        {
            errors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_7fe716eec7434f6a9a1579d2874b5583.Models;

public class AppointmentModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = "";

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = "";

    [Required(ErrorMessage = "Phone is required.")]
    public string Phone { get; set; } = "";

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = "";

    // Step 2
    [Required(ErrorMessage = "Please select a doctor.")]
    public string PreferredDoctor { get; set; } = "";

    [Required(ErrorMessage = "Date is required.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string TimeSlot { get; set; } = "";

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters.")]
    public string ReasonForVisit { get; set; } = "";

    public bool IsDateInFuture()
    {
        return AppointmentDate.HasValue && AppointmentDate.Value > DateOnly.FromDateTime(DateTime.Today);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_7fe716eec7434f6a9a1579d2874b5583.Models
@using sv_7fe716eec7434f6a9a1579d2874b5583.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3>Book a Medical Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    @* ── STEP 1 ── *@
    <fieldset>
        <legend>Step 1: Patient Information</legend>

        <div class="mb-3">
            <label for="patientName" class="form-label">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label for="email" class="form-label">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (serverErrors.ContainsKey("Email"))
            {
                <div class="validation-message">@serverErrors["Email"]</div>
            }
        </div>

        <div class="mb-3">
            <label for="phone" class="form-label">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label for="insurance" class="form-label">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>
    </fieldset>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
            Next
        </button>
    }

    @* ── STEP 2 ── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Step 2: Appointment Details</legend>

            <div class="mb-3">
                <label for="doctor" class="form-label">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="Model.PreferredDoctor"
                    @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.PreferredDoctor" />
                @if (serverErrors.ContainsKey("PreferredDoctor"))
                {
                    <div class="validation-message">@serverErrors["PreferredDoctor"]</div>
                }
            </div>

            <div class="mb-3">
                <label for="date" class="form-label">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate"
                    @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => Model.AppointmentDate" />
                @if (dateError is not null)
                {
                    <div class="validation-message">@dateError</div>
                }
            </div>

            <div class="mb-3">
                <label for="timeslot" class="form-label">Time Slot</label>
                <InputSelect id="timeslot" class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
                @if (serverErrors.ContainsKey("TimeSlot"))
                {
                    <div class="validation-message">@serverErrors["TimeSlot"]</div>
                }
            </div>

            <div class="mb-3">
                <label for="reason" class="form-label">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" rows="3" @bind-Value="Model.ReasonForVisit" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-outline-secondary me-2" @onclick="BackToStep1">
                Back
            </button>
            <button type="button" class="btn btn-primary me-2" @onclick="CheckAvailability" disabled="@isSubmitting">
                @(isSubmitting ? "Checking…" : "Check Availability")
            </button>

            @if (availabilityChecked && !serverErrors.Any())
            {
                <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                    Confirm Appointment
                </button>
            }
        </fieldset>
    }
</EditForm>

@if (submitted)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully for <strong>@Model.PatientName</strong>
        with <strong>@Model.PreferredDoctor</strong>
        on @Model.AppointmentDate?.ToString("MMMM d, yyyy") at @Model.TimeSlot.
    </div>
}

@code {
    private AppointmentModel Model { get; set; } = new();
    private List<string> doctors = new();
    private List<string> timeSlots = new();
    private Dictionary<string, string> serverErrors = new();

    private bool showStep2;
    private bool availabilityChecked;
    private bool isSubmitting;
    private bool submitted;
    private string? dateError;

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate step 1 fields manually
        if (string.IsNullOrWhiteSpace(Model.PatientName)
            || string.IsNullOrWhiteSpace(Model.Email)
            || string.IsNullOrWhiteSpace(Model.Phone)
            || string.IsNullOrWhiteSpace(Model.InsuranceProvider))
        {
            return;
        }

        if (!new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email))
        {
            return;
        }

        showStep2 = true;
    }

    private void BackToStep1()
    {
        showStep2 = false;
        availabilityChecked = false;
        serverErrors.Clear();
        dateError = null;
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityChecked = false;
        serverErrors.Clear();
        Model.TimeSlot = "";

        if (!string.IsNullOrWhiteSpace(Model.PreferredDoctor) && Model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.PreferredDoctor, Model.AppointmentDate.Value);
        }
        else
        {
            timeSlots.Clear();
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        dateError = null;
        availabilityChecked = false;

        // Client-side step 2 validation
        if (string.IsNullOrWhiteSpace(Model.PreferredDoctor)
            || !Model.AppointmentDate.HasValue
            || string.IsNullOrWhiteSpace(Model.TimeSlot)
            || string.IsNullOrWhiteSpace(Model.ReasonForVisit))
        {
            return;
        }

        if (Model.ReasonForVisit.Length > 500)
        {
            return;
        }

        if (!Model.IsDateInFuture())
        {
            dateError = "Date must be in the future.";
            return;
        }

        isSubmitting = true;
        try
        {
            serverErrors = await AppointmentService.ValidatePatientAsync(
                Model.Email,
                Model.InsuranceProvider,
                Model.PreferredDoctor,
                Model.TimeSlot);

            availabilityChecked = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private void HandleSubmit()
    {
        if (serverErrors.Any())
            return;

        submitted = true;
    }
}

